     */
    fun `saveConversation`(`id`: kotlin.String, `title`: kotlin.String, `messages`: kotlin.String, `apiHistory`: kotlin.String): ConversationData
    
    fun `setSetting`(`key`: kotlin.String, `value`: kotlin.String)
    
    /**
