public object FfiConverterTypeNionCore: FfiConverter<NionCore, Long> {
    override fun lower(value: NionCore): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): NionCore {
        return NionCore(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): NionCore {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: NionCore) = 8UL

    override fun write(value: NionCore, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



