sealed class NionException: kotlin.Exception() {
    
    class DatabaseException(
        
        val `msg`: kotlin.String
        ) : NionException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class NotFound(
        
        val `msg`: kotlin.String
        ) : NionException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    
    class ValidationException(
        
        val `msg`: kotlin.String
        ) : NionException() {
        override val message
            get() = "msg=${ `msg` }"
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<NionException> {
        override fun lift(error_buf: RustBuffer.ByValue): NionException = FfiConverterTypeNionError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeNionError : FfiConverterRustBuffer<NionException> {
    override fun read(buf: ByteBuffer): NionException {
        

        return when(buf.getInt()) {
            1 -> NionException.DatabaseException(
                FfiConverterString.read(buf),
                )
            2 -> NionException.NotFound(
                FfiConverterString.read(buf),
                )
            3 -> NionException.ValidationException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: NionException): ULong {
        return when(value) {
            is NionException.DatabaseException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is NionException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
            is NionException.ValidationException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.`msg`)
            )
        }
    }

    override fun write(value: NionException, buf: ByteBuffer) {
        when(value) {
            is NionException.DatabaseException -> {
                buf.putInt(1)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is NionException.NotFound -> {
                buf.putInt(2)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
            is NionException.ValidationException -> {
                buf.putInt(3)
                FfiConverterString.write(value.`msg`, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}




/**
 * @suppress
 */
public object FfiConverterOptionalString: FfiConverterRustBuffer<kotlin.String?> {
    override fun read(buf: ByteBuffer): kotlin.String? {
        if (buf.get().toInt() == 0) {
            return null
        }
        return FfiConverterString.read(buf)
    }

    override fun allocationSize(value: kotlin.String?): ULong {
        if (value == null) {
            return 1UL
        } else {
            return 1UL + FfiConverterString.allocationSize(value)
        }
    }

    override fun write(value: kotlin.String?, buf: ByteBuffer) {
        if (value == null) {
            buf.put(0)
        } else {
            buf.put(1)
            FfiConverterString.write(value, buf)
        }
    }
}




/**
 * @suppress
 */
public object FfiConverterSequenceString: FfiConverterRustBuffer<List<kotlin.String>> {
    override fun read(buf: ByteBuffer): List<kotlin.String> {
        val len = buf.getInt()
        return List<kotlin.String>(len) {
            FfiConverterString.read(buf)
        }
    }

    override fun allocationSize(value: List<kotlin.String>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterString.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

    override fun write(value: List<kotlin.String>, buf: ByteBuffer) {
        buf.putInt(value.size)
        value.iterator().forEach {
            FfiConverterString.write(it, buf)
        }
    }
}




